import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Game of Life", () => {
  it("should return an empty grid when given an empty grid", () => {
    expect(nextGeneration([])).toEqual([]);
  });
  it("should kill a single live cell (underpopulation)", () => {
    expect(nextGeneration([[0, 0]])).toEqual([]);
  });
  it("should kill a live cell with only one neighbor (underpopulation)", () => {
    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
  });
  it("should keep a live cell alive with exactly two neighbors (survival)", () => {
    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
    const sorted = result.map(([x, y]) => [x, y]).sort((a, b) => a[0] - b[0] || a[1] - b[1]);
    expect(sorted).toEqual([[1, -1], [1, 0], [1, 1]]);
  });
  it.todo("should keep a live cell alive with exactly three neighbors (survival)");
  it.todo("should kill a live cell with four neighbors (overpopulation)");
  it.todo("should create a live cell from a dead cell with exactly three live neighbors (reproduction)");
  it.todo("should not create a live cell from a dead cell with only two live neighbors");
  it.todo("should handle a block still life (2x2 square remains unchanged)");
  it.todo("should handle a blinker oscillator (three in a row toggles orientation)");
  it.todo("should support negative coordinates");
});

